#!/bin/bash

# Ensure password complexity is set to require at least one special character
sed -i '/password requisite pam_pwquality.so retry=3 minlen=8 difok=3 ucredit=-1 lcredit=-1 dcredit=-1 ocredit=-1 / s/^.*$/password requisite pam_pwquality.so retry=3 minlen=8 difok=3 ucredit=-1 lcredit=-1 dcredit=-1 ocredit=-2 /' /etc/pam.d/common-password

#!/bin/bash

# Disable loading of replacement kernel images
grubby --update-kernel=ALL --remove-kernel=ALL

#!/bin/bash

systemctl enable file-access-policy-daemon.service
systemctl start file-access-policy-daemon.service

#!/bin/bash

# Set default runlevel to 3 for multi-user, non-graphical mode
systemctl set-default multi-user.target

#!/bin/bash

# Ensure auditd is running
systemctl is-active --quiet auditd && systemctl restart auditd || exit 1

# Load the audit rule if it does not exist
auditctl -l | grep 'type=exec,perm=x,uid>=1000,auid>=500' > /dev/null || {
    auditctl -w /usr/bin/ssh-keysign -p x -k privileged
}

# Ensure the audit rule is persistent across reboots
echo "type=exec,perm=x,uid>=1000,auid>=500" >> /etc/audit/rules.d/privileged.rules

exit 0
